// DecodeDownloadPluginPackageRequest returns a decoder for requests sent to
// the plugins downloadPluginPackage endpoint.
func DecodeDownloadPluginPackageRequest(mux goahttp.Muxer, decoder func(*http.Request) goahttp.Decoder) func(*http.Request) (*plugins.DownloadPluginPackagePayload, error) {
	return func(r *http.Request) (*plugins.DownloadPluginPackagePayload, error) {
		var payload *plugins.DownloadPluginPackagePayload
		var (
			pluginID         string
			platform         string
			sessionToken     *string
			projectSlugInput *string
			err              error
		)
		qp := r.URL.Query()
		pluginID = qp.Get("plugin_id")
		if pluginID == "" {
			err = goa.MergeErrors(err, goa.MissingFieldError("plugin_id", "query string"))
		}
		err = goa.MergeErrors(err, goa.ValidateFormat("plugin_id", pluginID, goa.FormatUUID))
		platform = qp.Get("platform")
		if platform == "" {
			err = goa.MergeErrors(err, goa.MissingFieldError("platform", "query string"))
		}
		if !(platform == "claude" || platform == "cursor") {
			err = goa.MergeErrors(err, goa.InvalidEnumValueError("platform", platform, []any{"claude", "cursor"}))
		}
		sessionTokenRaw := r.Header.Get("Gram-Session")
		if sessionTokenRaw != "" {
			sessionToken = &sessionTokenRaw
		}
		projectSlugInputRaw := r.Header.Get("Gram-Project")
		if projectSlugInputRaw != "" {
			projectSlugInput = &projectSlugInputRaw
		}
		if err != nil {
			return payload, err
		}
		payload = NewDownloadPluginPackagePayload(pluginID, platform, sessionToken, projectSlugInput)
		if payload.SessionToken != nil {
			if strings.Contains(*payload.SessionToken, " ") {
				// Remove authorization scheme prefix (e.g. "Bearer")
				cred := strings.SplitN(*payload.SessionToken, " ", 2)[1]
				payload.SessionToken = &cred
			}
		}
		if payload.ProjectSlugInput != nil {
			if strings.Contains(*payload.ProjectSlugInput, " ") {
				// Remove authorization scheme prefix (e.g. "Bearer")
				cred := strings.SplitN(*payload.ProjectSlugInput, " ", 2)[1]
				payload.ProjectSlugInput = &cred
			}
		}

		return payload, nil
	}
}

